// Кириллический сабсет шрифта Roboto Regular для встраивания в PDF (jsPDF, MLC-052).
//
// Шрифт: Roboto Regular, версия 2.137 (классический Roboto, Christian Robertson / Google).
// Лицензия: Apache License 2.0 (https://github.com/googlefonts/roboto) — допускает
// встраивание и распространение. Источник TTF: @expo-google-fonts/roboto (jsdelivr).
// Сабсет: Basic Latin + Latin-1 supplement + весь блок Cyrillic (U+0400–04FF) + ходовая
// типографика, инструмент subset-font (harfbuzz, без Python). Полный шрифт не нужен:
// стандартные шрифты jsPDF (Helvetica и пр.) НЕ содержат кириллицу — без встроенного TTF
// русский текст выводится пустыми глифами. Регенерация — см. историю MLC-052.
//
// Хранится как base64 (а не бинарный ассет): jsPDF.addFileToVFS принимает строку base64,
// и так файл едет тем же путём, что и весь модуль экспорта (lazy-чанк по клику).

/* prettier-ignore */
export const ROBOTO_REGULAR_BASE64 =
"";

/** Имя файла во VFS jsPDF и postScriptName для setFont. */
export const ROBOTO_VFS_FILENAME = "Roboto-Regular.ttf";
export const ROBOTO_FONT_NAME = "Roboto";
